<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\StoreSliderRequest; use App\Http\Requests\Admin\UpdateSliderRequest; use App\Models\Slider; use App\Services\FileUploadService; use Illuminate\Http\RedirectResponse; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class SliderController extends Controller { public function index(): View { $items=Slider::query()->ordered()->paginate(15); return view('admin.pages.sliders.index',compact('items')); } public function create(): View { return view('admin.pages.sliders.form',['item'=>new Slider()]); } public function store(StoreSliderRequest $request, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),null,'uploads/sliders'); Slider::create($data); $this->clearCache(); return redirect()->route('admin.sliders.index')->with('success','Slider created successfully.'); } public function edit(Slider $slider): View { return view('admin.pages.sliders.form',['item'=>$slider]); } public function update(UpdateSliderRequest $request, Slider $slider, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),$slider->image,'uploads/sliders'); $slider->update($data); $this->clearCache(); return redirect()->route('admin.sliders.index')->with('success','Slider updated successfully.'); } public function destroy(Slider $slider): RedirectResponse { $slider->delete(); $this->clearCache(); return back()->with('success','Slider deleted successfully.'); } private function payload(array $data): array { $data['status']=(bool)($data['status']??false); $data['sort_order']=(int)($data['sort_order']??0); return $data; } private function clearCache(): void { Cache::forget('sliders_active_ordered'); } }
